// (Phần import và setup giữ nguyên)
// Trong hàm handleSubmit:

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!selectedArea) return alert("Chọn khu vực!");

    // CHECK ALL ITEMS
    const missingItems = checklistConfig.filter(config => !currentStatusMap[config.item]);
    if (missingItems.length > 0) {
      alert(`Vui lòng kiểm tra hết các mục: ${missingItems.map(c => c.item).join(', ')}`);
      return; // CHẶN SUBMIT
    }

    // Gửi log lên server
    checklistConfig.forEach(config => {
      addFacilityLog({
        staffName: user.name,
        type: checkType,
        area: selectedArea,
        item: config.item,
        status: currentStatusMap[config.item]
      });
    });

    // POPUP SUCCESS
    alert("✅ Báo cáo đã gửi thành công về máy chủ!");
    
    // Clear temp data
    setTempData(prev => {
      const newData = { ...prev };
      delete newData[currentKey]; 
      return newData;
    });
  };
